462	function renderImages(images) {
463	 return `<div class="img-grid">${images.map(([type, src, label]) => `
464	 <div class="img-card">
465	 <img src="${src}" alt="${label}">
466	 <div class="img-label"><span class="img-tag ${type}">${type === 'catalog' ? '카탈로그' : type === 'booth-ref' ? '부스 참고' : '부스'}</span>${label}</div>
467	 </div>`).join('')}</div>`;
468	}
