470	function renderSKUBox(s) {
471	 if (!s.sku) return '';
472	 return `<div class="sku-box">
473	 <h4>${s.skuTitle || '요청 SKU'}</h4>
474	 <ul>${listHTML(s.sku)}</ul>
475	 ${s.excluded ? `<div class="excluded">${s.excluded}</div>` : ''}
476	 </div>`;
477	}
478	
479	function renderQList(title, items) {
480	 if (!items || !items.length) return '';
481	 return `<div class="q-list">
482	 <div class="q-title">${title}</div>
483	 <ul>${listHTML(items)}</ul>
484	 </div>`;
485	}
486	
487	function renderSeriesCard(s) {
488	 return `<div class="series-card">
489	 <h3>${s.title}</h3>
490	 ${s.meta ? `<div class="series-meta">${s.meta}</div>` : ''}
491	 ${renderImages(s.images)}
492	 ${renderSKUBox(s)}
493	 ${renderQList(s.qTitle || '핵심 질문', s.questions)}
494	 </div>`;
495	}
