497	function renderContactCard(f) {
498	 const rows = f.contact.map(([k, v, urgent]) =>
499	 `<div class="row"><b${urgent ? ' class="urgent"' : ''}>${k}</b> ${v}</div>`
500	 ).join('');
501	 return `<div class="contact-card${f.contactWarn ? ' warn' : ''}">${rows}</div>`;
502	}
