504	function renderFactoryTab(f) {
505	 const factoryQ = f.factoryQList
506	 ? `<section><h2><span class="icon">⭐</span>${f.factoryQList.heading}</h2>${renderQList(f.factoryQList.title, f.factoryQList.items)}</section>`
